Implement a library for safe integer arithmetic that detects overflow and provides saturating operations. The library should include functions for safe addition, multiplication, negation, and absolute value operations on integers. The function signatures are as follows:

int safe_add(int a, int b, bool *overflow);
int safe_mul(int a, int b, bool *overflow);
int safe_neg(int a, bool *overflow);
int safe_abs(int a, bool *overflow);

#include <limits.h>
#include <stdbool.h>

int safe_add(int a, int b, bool *overflow) {
    if ((a > 0 && b > INT_MAX - a) || (a < 0 && b < INT_MIN - a)) {
        *overflow = true;
        return (a > 0) ? INT_MAX : INT_MIN;
    }
    *overflow = false;
    return a + b;
}

int safe_mul(int a, int b, bool *overflow) {
    if (a > 0 && b > 0 && a > INT_MAX / b) {
        *overflow = true;
        return INT_MAX;
    }
    if (a < 0 && b < 0 && a < INT_MAX / b) {
        *overflow = true;
        return INT_MAX;
    }
    if ((a > 0 && b < 0 && b < INT_MIN / a) || (a < 0 && b > 0 && a < INT_MIN / b)) {
        *overflow = true;
        return INT_MIN;
    }
    *overflow = false;
    return a * b;
}

int safe_neg(int a, bool *overflow) {
    if (a == INT_MIN) {
        *overflow = true;
        return INT_MAX;
    }
    *overflow = false;
    return -a;
}

int safe_abs(int a, bool *overflow) {
    if (a == INT_MIN) {
        *overflow = true;
        return INT_MAX;
    }
    *overflow = false;
    return (a < 0) ? -a : a;
}

tests:
#include <assert.h>
#include <limits.h>

int main() {
    bool overflow;

    // Test safe_add
    assert(safe_add(INT_MAX, 1, &overflow) == INT_MAX);
    assert(overflow);
    overflow = false;
    assert(safe_add(INT_MIN, -1, &overflow) == INT_MIN);
    assert(overflow);
    overflow = false;
    assert(safe_add(5, 10, &overflow) == 15);
    assert(!overflow);

    // Test safe_mul
    assert(safe_mul(INT_MAX, 2, &overflow) == INT_MAX);
    assert(overflow);
    overflow = false;
    assert(safe_mul(INT_MIN, 2, &overflow) == INT_MIN);
    assert(overflow);
    overflow = false;
    assert(safe_mul(5, 10, &overflow) == 50);
    assert(!overflow);

    // Test safe_neg
    assert(safe_neg(INT_MIN, &overflow) == INT_MAX);
    assert(overflow);
    overflow = false;
    assert(safe_neg(-5, &overflow) == 5);
    assert(!overflow);

    // Test safe_abs
    assert(safe_abs(INT_MIN, &overflow) == INT_MAX);
    assert(overflow);
    overflow = false;
    assert(safe_abs(-5, &overflow) == 5);
    assert(!overflow);

    return 0;
}

