#include <limits.h>
#include <stdbool.h>

int add_safe(int a, int b, bool *overflow) {
    if ((b > 0 && a > INT_MAX - b) || (b < 0 && a < INT_MIN - b)) {
        *overflow = true;
        return (a > 0) ? INT_MAX : INT_MIN;
    } else {
        *overflow = false;
        return a + b;
    }
}

int mul_safe(int a, int b, bool *overflow) {
    if (a > 0) {
        if (b > 0 && a > INT_MAX / b) {
            *overflow = true;
            return INT_MAX;
        } else if (b < 0 && b < INT_MIN / a) {
            *overflow = true;
            return INT_MIN;
        }
    } else if (a < 0) {
        if (b > 0 && a < INT_MIN / b) {
            *overflow = true;
            return INT_MIN;
        } else if (b < 0 && a > INT_MAX / b) {
            *overflow = true;
            return INT_MAX;
        }
    }
    *overflow = false;
    return a * b;
}

int negate_safe(int a, bool *overflow) {
    if (a == INT_MIN) {
        *overflow = true;
        return INT_MAX;
    } else {
        *overflow = false;
        return -a;
    }
}

int abs_safe(int a, bool *overflow) {
    if (a == INT_MIN) {
        *overflow = true;
        return INT_MAX;
    } else {
        *overflow = false;
        return (a < 0) ? -a : a;
    }
}

tests:
#include <assert.h>
#include <limits.h>
#include <stdbool.h>

int main() {
    bool overflow;

    // Test add_safe
    assert(add_safe(INT_MAX, 1, &overflow) == INT_MAX);
    assert(overflow == true);
    assert(add_safe(INT_MIN, -1, &overflow) == INT_MIN);
    assert(overflow == true);
    assert(add_safe(10, 20, &overflow) == 30);
    assert(overflow == false);

    // Test mul_safe
    assert(mul_safe(INT_MAX, 2, &overflow) == INT_MAX);
    assert(overflow == true);
    assert(mul_safe(INT_MIN, 2, &overflow) == INT_MIN);
    assert(overflow == true);
    assert(mul_safe(10, 20, &overflow) == 200);
    assert(overflow == false);

    // Test negate_safe
    assert(negate_safe(INT_MIN, &overflow) == INT_MAX);
    assert(overflow == true);
    assert(negate_safe(-10, &overflow) == 10);
    assert(overflow == false);

    // Test abs_safe
    assert(abs_safe(INT_MIN, &overflow) == INT_MAX);
    assert(overflow == true);
    assert(abs_safe(-10, &overflow) == 10);
    assert(overflow == false);
    assert(abs_safe(10, &overflow) == 10);
    assert(overflow == false);

    return 0;
}

