#include <limits.h>
#include <stdbool.h>

bool canPartition(int* nums, int numsSize) {
    int totalSum = 0;
    for (int i = 0; i < numsSize; i++) {
        totalSum += nums[i];
    }

    if (totalSum % 2 != 0) {
        return false;
    }

    int target = totalSum / 2;
    bool dp[numsSize + 1][target + 1];

    for (int i = 0; i <= numsSize; i++) {
        dp[i][0] = true;
    }
    for (int j = 1; j <= target; j++) {
        dp[0][j] = false;
    }

    for (int i = 1; i <= numsSize; i++) {
        for (int j = 1; j <= target; j++) {
            if (nums[i - 1] > j) {
                dp[i][j] = dp[i - 1][j];
            } else {
                dp[i][j] = dp[i - 1][j] || dp[i - 1][j - nums[i - 1]];
            }
        }
    }

    return dp[numsSize][target];
}

tests:
#include <assert.h>
#include <limits.h>

int main() {
    int nums1[] = {1, 5, 11, 5};
    int numsSize1 = sizeof(nums1) / sizeof(nums1[0]);
    assert(canPartition(nums1, numsSize1) == true);

    int nums2[] = {1, 2, 3, 5};
    int numsSize2 = sizeof(nums2) / sizeof(nums2[0]);
    assert(canPartition(nums2, numsSize2) == false);

    int nums3[] = {0, 0, 0, 0};
    int numsSize3 = sizeof(nums3) / sizeof(nums3[0]);
    assert(canPartition(nums3, numsSize3) == true);

    int nums4[] = {1, 2, 3, 4, 5, 6, 7, 8, 9};
    int numsSize4 = sizeof(nums4) / sizeof(nums4[0]);
    assert(canPartition(nums4, numsSize4) == false);

    return 0;
}

