#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <ctype.h>

typedef struct { char *filteredString; int alphaCount; } FilterResult;

FilterResult filterAndCount(const char *input) {
    int length = strlen(input);
    FilterResult result;
    result.filteredString = (char *)malloc(length + 1);
    if (!result.filteredString) {
        result.filteredString = NULL;
        result.alphaCount = 0;
        return result;
    }

    int index = 0;
    for (int i = 0; i < length; i++) {
        if (isalpha(input[i])) {
            result.filteredString[index++] = tolower(input[i]);
        }
    }
    result.filteredString[index] = '\0';
    result.alphaCount = index;

    return result;
}

tests:
#include <assert.h>
#include <string.h>

int main() {
    FilterResult result = filterAndCount("Hello, World! 123");
    assert(strcmp(result.filteredString, "helloworld") == 0);
    assert(result.alphaCount == 10);
    free(result.filteredString);

    result = filterAndCount("C123oding");
    assert(strcmp(result.filteredString, "coding") == 0);
    assert(result.alphaCount == 6);
    free(result.filteredString);

    result = filterAndCount("1234567890");
    assert(strcmp(result.filteredString, "") == 0);
    assert(result.alphaCount == 0);
    free(result.filteredString);

    return 0;
}

