#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <ctype.h>

 typedef struct {
    int alphanumericCount;
    int spaceCount;
    int punctuationCount;
} TextAnalysis;

TextAnalysis* analyzeText(const char* text) {
    TextAnalysis* analysis = (TextAnalysis*)malloc(sizeof(TextAnalysis));
    analysis->alphanumericCount = 0;
    analysis->spaceCount = 0;
    analysis->punctuationCount = 0;

    int i = 0;
    while (text[i] != '\0') {
        if (isspace(text[i])) {
            analysis->spaceCount++;
        } else if (isalpha(text[i]) || isdigit(text[i])) {
            analysis->alphanumericCount++;
        } else {
            analysis->punctuationCount++;
        }
        i++;
    }

    return analysis;
}

tests:
#include <assert.h>

int main() {
    TextAnalysis* analysis = analyzeText("Hello, World!");
    assert(analysis->alphanumericCount == 10);
    assert(analysis->spaceCount == 1);
    assert(analysis->punctuationCount == 2);

    free(analysis);
    return 0;
}

