You are developing a data validation library for a new embedded system. Your task is to implement two boolean predicate functions: one to check if an array of integers is sorted in non-decreasing order, and another to check if a given integer is a power of two. The function signatures must be:

bool is_sorted(int arr[], int size);
bool is_power_of_two(int num);

Implement these functions using the <stdbool.h> header to return true or false.

#include <stdbool.h>

bool is_sorted(int arr[], int size) {
    for (int i = 0; i < size - 1; i++) {
        if (arr[i] > arr[i + 1]) {
            return false;
        }
    }
    return true;
}

bool is_power_of_two(int num) {
    if (num <= 0) {
        return false;
    }
    return (num & (num - 1)) == 0;
}

tests:
#include <assert.h>

int main() {
    int arr1[] = {1, 2, 3, 4, 5};
    int arr2[] = {5, 4, 3, 2, 1};
    int arr3[] = {1, 3, 2, 4, 5};

    assert(is_sorted(arr1, 5) == true);
    assert(is_sorted(arr2, 5) == false);
    assert(is_sorted(arr3, 5) == false);

    assert(is_power_of_two(1) == true);
    assert(is_power_of_two(2) == true);
    assert(is_power_of_two(3) == false);
    assert(is_power_of_two(4) == true);
    assert(is_power_of_two(0) == false);
    assert(is_power_of_two(-1) == false);

    return 0;
}

