#include <stdbool.h>

bool is_balanced(int arr[], int size) {
    if (size <= 1) return true;

    int total_sum = 0;
    for (int i = 0; i < size; i++) {
        total_sum += arr[i];
    }

    int left_sum = 0;
    for (int i = 0; i < size; i++) {
        if (left_sum == (total_sum - arr[i] - left_sum)) {
            return true;
        }
        left_sum += arr[i];
    }

    return false;
}

tests:
#include <assert.h>

int main() {
    int arr1[] = {1, 7, 3, 6, 5, 6};
    assert(is_balanced(arr1, 6) == true);

    int arr2[] = {1, 2, 3};
    assert(is_balanced(arr2, 3) == false);

    int arr3[] = {2, 1, -1};
    assert(is_balanced(arr3, 3) == true);

    int arr4[] = {10};
    assert(is_balanced(arr4, 1) == true);

    int arr5[] = {};
    assert(is_balanced(arr5, 0) == true);

    return 0;
}

