struct SquareInfo nearestPerfectSquare(int num) {
    struct SquareInfo result;
    result.original = num;
    int root = (int)sqrt(num);
    result.nearestSquare = root * root;
    if (num - root * root > (root + 1) * (root + 1) - num) {
        result.nearestSquare = (root + 1) * (root + 1);
    }
    result.isPerfect = result.nearestSquare == num;
    return result;
}

