#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <ctype.h>

#define MAX_TOKENS 100
#define MAX_TOKEN_LEN 100

typedef struct {
    char **tokens;
    int token_count;
    int letter_count;
    int digit_count;
    int other_count;
} TokenizedText;

void tokenize_text(const char *input, TokenizedText *output) {
    output->tokens = (char **)malloc(MAX_TOKENS * sizeof(char *));
    for (int i = 0; i < MAX_TOKENS; i++) {
        output->tokens[i] = (char *)malloc(MAX_TOKEN_LEN * sizeof(char));
    }
    output->token_count = 0;
    output->letter_count = 0;
    output->digit_count = 0;
    output->other_count = 0;

    int token_len = 0;
    int token_index = 0;
    for (const char *p = input; *p != '\0'; p++) {
        if (isspace((unsigned char)*p)) {
            continue;
        }
        if (isalpha((unsigned char)*p)) {
            output->tokens[token_index][token_len] = tolower((unsigned char)*p);
            token_len++;
            output->letter_count++;
        } else if (isdigit((unsigned char)*p)) {
            output->tokens[token_index][token_len] = *p;
            token_len++;
            output->digit_count++;
        } else {
            if (token_len > 0) {
                output->tokens[token_index][token_len] = '\0';
                token_index++;
                token_len = 0;
            }
            output->other_count++;
        }
    }
    if (token_len > 0) {
        output->tokens[token_index][token_len] = '\0';
        token_index++;
    }
    output->token_count = token_index;
}

void free_tokenized_text(TokenizedText *output) {
    for (int i = 0; i < output->token_count; i++) {
        free(output->tokens[i]);
    }
    free(output->tokens);
}

tests:
#include <assert.h>

int main() {
    TokenizedText result;
    tokenize_text("Hello, World! 123", &result);
    assert(result.token_count == 3);
    assert(strcmp(result.tokens[0], "hello") == 0);
    assert(strcmp(result.tokens[1], "world") == 0);
    assert(strcmp(result.tokens[2], "123") == 0);
    assert(result.letter_count == 10);
    assert(result.digit_count == 3);
    assert(result.other_count == 2);
    free_tokenized_text(&result);

    return 0;
}

