#include <math.h>
#include <stdbool.h>

enum NumberType {
    PERFECT_SQUARE,
    PRIME_NUMBER,
    INTEGER_ROOT,
    NONE
};

typedef enum NumberType NumberType;

bool isPerfectSquare(int n) {
    if (n < 0) return false;
    int root = (int)sqrt(n);
    return root * root == n;
}

bool isPrime(int n) {
    if (n <= 1) return false;
    if (n <= 3) return true;
    if (n % 2 == 0 || n % 3 == 0) return false;
    for (int i = 5; i * i <= n; i += 6) {
        if (n % i == 0 || n % (i + 2) == 0) return false;
    }
    return true;
}

NumberType checkNumberType(int n) {
    if (isPerfectSquare(n)) {
        return PERFECT_SQUARE;
    }
    if (isPrime(n)) {
        return PRIME_NUMBER;
    }
    int root = (int)sqrt(n);
    if (root * root <= n && n < (root + 1) * (root + 1)) {
        return INTEGER_ROOT;
    }
    return NONE;
}

