#include <stdbool.h>

bool is_balanced(int arr[], int size) {
    if (size <= 1) {
        return true;
    }

    for (int i = 0; i < size; i++) {
        int left_sum = 0;
        int right_sum = 0;

        for (int j = 0; j < i; j++) {
            left_sum += arr[j];
        }

        for (int j = i + 1; j < size; j++) {
            right_sum += arr[j];
        }

        if (left_sum == right_sum) {
            return true;
        }
    }

    return false;
}

