// Function to calculate the distance between two points
double distance(double x1, double y1, double x2, double y2) {
    return sqrt(pow(x2 - x1, 2) + pow(y2 - y1, 2));
}

// Function to calculate the mean of an array
double mean(double arr[], int size) {
    double sum = 0.0;
    for (int i = 0; i < size; i++) {
        sum += arr[i];
    }
    return sum / size;
}

// Function to calculate the standard deviation of an array
// given the mean
// std = sqrt( sum( (x - mean)^2 ) / N )
double standard_deviation(double arr[], int size, double mean) {
    double sum = 0.0;
    for (int i = 0; i < size; i++) {
        sum += pow(arr[i] - mean, 2);
    }
    return sqrt(sum / size);
}

// Function to solve quadratic equation ax^2 + bx + c = 0
int quadratic_roots(double a, double b, double c, double *root1, double *root2) {
    double discriminant = pow(b, 2) - 4 * a * c;
    if (discriminant < 0) {
        return 0; // No real roots
    } else if (discriminant == 0) {
        *root1 = -b / (2 * a);
        return 1; // One real root
    } else {
        *root1 = (-b + sqrt(discriminant)) / (2 * a);
        *root2 = (-b - sqrt(discriminant)) / (2 * a);
        return 2; // Two real roots
    }
}

