bool are_valid_parentheses(const char *s) {
    int stack_size = strlen(s);
    char *stack = (char *)malloc(stack_size * sizeof(char));
    int top = -1;

    for (int i = 0; s[i] != '\0'; i++) {
        if (s[i] == '(' || s[i] == '{' || s[i] == '[') {
            stack[++top] = s[i];
        } else {
            if (top == -1) {
                free(stack);
                return false;
            }
            char top_char = stack[top--];
            if ((s[i] == ')' && top_char != '(') ||
                (s[i] == '}' && top_char != '{') ||
                (s[i] == ']' && top_char != '[')) {
                free(stack);
                return false;
            }
        }
    }
    bool result = (top == -1);
    free(stack);
    return result;
}

