struct Statistics {
    float mean;
    float stddev;
    float min;
    float max;
};

struct Statistics calculate_statistics(float* data, int length) {
    struct Statistics stats;
    if (length == 0) {
        stats.mean = 0.0;
        stats.stddev = 0.0;
        stats.min = 0.0;
        stats.max = 0.0;
        return stats;
    }

    float sum = 0.0;
    stats.min = data[0];
    stats.max = data[0];

    for (int i = 0; i < length; i++) {
        sum += data[i];
        if (data[i] < stats.min) {
            stats.min = data[i];
        }
        if (data[i] > stats.max) {
            stats.max = data[i];
        }
    }

    stats.mean = sum / length;

    float variance_sum = 0.0;
    for (int i = 0; i < length; i++) {
        variance_sum += pow(data[i] - stats.mean, 2);
    }
    stats.stddev = sqrt(variance_sum / length);

    return stats;
}

float distance(float x1, float y1, float x2, float y2) {
    return sqrt(pow(x2 - x1, 2) + pow(y2 - y1, 2));
}

