A flag is considered valid if it is a power of two or zero. A combination is valid if it can be expressed as a sum of distinct powers of two.

#include <stdbool.h>

bool is_power_of_two(int n) {
    return n > 0 && (n & (n - 1)) == 0;
}

bool are_valid_flags(int flags[], int size) {
    for (int i = 0; i < size; i++) {
        if (!is_power_of_two(flags[i]) && flags[i] != 0) {
            return false;
        }
    }
    return true;
}

bool is_valid_flag_combination(int flag) {
    return flag >= 0;
}

