#include <ctype.h>
#include <stdbool.h>

int parse_number(const char *input) {
    int result = 0;
    bool negative = false;
    bool found_digit = false;

    while (*input) {
        if (isspace((unsigned char)*input)) {
            input++;
            continue;
        }
        if (*input == '-' && !found_digit) {
            negative = true;
            input++;
            continue;
        }
        if (*input == '+' && !found_digit) {
            input++;
            continue;
        }
        if (isdigit((unsigned char)*input)) {
            found_digit = true;
            result = result * 10 + (*input - '0');
            input++;
        } else {
            break;
        }
    }

    return negative ? -result : result;
}

