Write a function `is_all_unique` that takes an array of integers and its size as arguments. The function should return `true` if all elements in the array are unique, and `false` otherwise. Additionally, implement a function `has_even_odd_pair` that takes an array of integers and its size as arguments. This function should return `true` if there exists at least one pair of adjacent elements where one is even and the other is odd, and `false` otherwise. The solution must use the `bool` type from the `<stdbool.h>` header. The function signatures are as follows:

bool is_all_unique(int arr[], int size);
bool has_even_odd_pair(int arr[], int size);

#include <stdbool.h>
#include <stdio.h>

bool is_all_unique(int arr[], int size) {
    for (int i = 0; i < size; i++) {
        for (int j = i + 1; j < size; j++) {
            if (arr[i] == arr[j]) {
                return false;
            }
        }
    }
    return true;
}

bool has_even_odd_pair(int arr[], int size) {
    for (int i = 0; i < size - 1; i++) {
        if ((arr[i] % 2 == 0 && arr[i + 1] % 2 != 0) ||
            (arr[i] % 2 != 0 && arr[i + 1] % 2 == 0)) {
            return true;
        }
    }
    return false;
}

