Implement a safe arithmetic library for integers that prevents overflow. The library should include functions for safe addition, multiplication, negation, and absolute value. The functions should return true if an overflow occurs and false otherwise. The solution must use the <limits.h> header for INT_MAX and INT_MIN values. Define the following functions:
- bool safe_add(int a, int b, int *result);
- bool safe_mul(int a, int b, int *result);
- bool safe_neg(int a, int *result);
- bool safe_abs(int a, int *result);

#include <limits.h>
#include <stdbool.h>

bool safe_add(int a, int b, int *result) {
    if (a > 0 && b > 0 && a > INT_MAX - b) {
        *result = INT_MAX;
        return true;
    }
    if (a < 0 && b < 0 && a < INT_MIN - b) {
        *result = INT_MIN;
        return true;
    }
    *result = a + b;
    return false;
}

bool safe_mul(int a, int b, int *result) {
    if (a > 0 && b > 0 && a > INT_MAX / b) {
        *result = INT_MAX;
        return true;
    }
    if (a < 0 && b > 0 && a < INT_MIN / b) {
        *result = INT_MIN;
        return true;
    }
    if (a > 0 && b < 0 && b < INT_MIN / a) {
        *result = INT_MIN;
        return true;
    }
    if (a < 0 && b < 0 && a < INT_MAX / b) {
        *result = INT_MAX;
        return true;
    }
    *result = a * b;
    return false;
}

bool safe_neg(int a, int *result) {
    if (a == INT_MIN) {
        *result = INT_MAX;
        return true;
    }
    *result = -a;
    return false;
}

bool safe_abs(int a, int *result) {
    if (a == INT_MIN) {
        *result = INT_MAX;
        return true;
    }
    *result = (a < 0) ? -a : a;
    return false;
}

tests:
#include <assert.h>
#include <limits.h>

int main() {
    int result;

    // Test safe_add
    assert(!safe_add(2, 3, &result) && result == 5);
    assert(safe_add(INT_MAX, 1, &result) && result == INT_MAX);
    assert(safe_add(INT_MIN, -1, &result) && result == INT_MIN);

    // Test safe_mul
    assert(!safe_mul(2, 3, &result) && result == 6);
    assert(safe_mul(INT_MAX, 2, &result) && result == INT_MAX);
    assert(safe_mul(INT_MIN, 2, &result) && result == INT_MIN);

    // Test safe_neg
    assert(!safe_neg(-5, &result) && result == 5);
    assert(safe_neg(INT_MIN, &result) && result == INT_MAX);

    // Test safe_abs
    assert(!safe_abs(-5, &result) && result == 5);
    assert(!safe_abs(5, &result) && result == 5);
    assert(safe_abs(INT_MIN, &result) && result == INT_MAX);

    return 0;
}

