#include <limits.h>

int add_safe(int a, int b, int* result) {
    if (b > 0 && a > INT_MAX - b) {
        *result = INT_MAX;
        return 1;
    } else if (b < 0 && a < INT_MIN - b) {
        *result = INT_MIN;
        return 1;
    }
    *result = a + b;
    return 0;
}

int mul_safe(int a, int b, int* result) {
    if (a > 0) {
        if (b > 0 && a > INT_MAX / b) {
            *result = INT_MAX;
            return 1;
        } else if (b < 0 && a < INT_MIN / b) {
            *result = INT_MIN;
            return 1;
        }
    } else if (a < 0) {
        if (b > 0 && a < INT_MIN / b) {
            *result = INT_MIN;
            return 1;
        } else if (b < 0 && a > INT_MAX / b) {
            *result = INT_MAX;
            return 1;
        }
    }
    *result = a * b;
    return 0;
}

int negate_safe(int a, int* result) {
    if (a == INT_MIN) {
        *result = INT_MIN;
        return 1;
    }
    *result = -a;
    return 0;
}

int abs_safe(int a, int* result) {
    if (a == INT_MIN) {
        *result = INT_MAX;
        return 1;
    }
    *result = a < 0 ? -a : a;
    return 0;
}

